 21→// Worker for either Archiving or Deleting files
 22→
 23→func CleanUp(wg *sync.WaitGroup, ctx context.Context) {
 24→	if Keys.Cleanup.Mode == "archive" {
 25→		cclog.Info("[METRICSTORE]> enable archive cleanup to parquet")
 26→		// Run as Archiver
 27→		cleanUpWorker(wg, ctx,
 28→			Keys.RetentionInMemory,
 29→			"archiving",
 30→			Keys.Cleanup.RootDir,
 31→			false,
 32→		)
 33→	} else {
 34→		// Run as Deleter
 35→		cleanUpWorker(wg, ctx,
 36→			Keys.RetentionInMemory,
 37→			"deleting",
 38→			"",
 39→			true,
 40→		)
 41→	}
 42→}
