 17→// JobToParquetRow converts job metadata and metric data into a flat ParquetJobRow.
 18→// Nested fields are marshaled to JSON; metric data is gzip-compressed JSON.
 19→func JobToParquetRow(meta *schema.Job, data *schema.JobData) (*ParquetJobRow, error) {
 20→	resourcesJSON, err := json.Marshal(meta.Resources)
 21→	if err != nil {
 22→		return nil, fmt.Errorf("marshal resources: %w", err)
 23→	}
 24→
 25→	var statisticsJSON []byte
 26→	if meta.Statistics != nil {
 27→		statisticsJSON, err = json.Marshal(meta.Statistics)
 28→		if err != nil {
 29→			return nil, fmt.Errorf("marshal statistics: %w", err)
 30→		}
 31→	}
 32→
 33→	var tagsJSON []byte
 34→	if len(meta.Tags) > 0 {
 35→		tagsJSON, err = json.Marshal(meta.Tags)
 36→		if err != nil {
 37→			return nil, fmt.Errorf("marshal tags: %w", err)
 38→		}
 39→	}
 40→
 41→	var metaDataJSON []byte
 42→	if meta.MetaData != nil {
 43→		metaDataJSON, err = json.Marshal(meta.MetaData)
 44→		if err != nil {
 45→			return nil, fmt.Errorf("marshal metadata: %w", err)
 46→		}
 47→	}
 48→
 49→	var footprintJSON []byte
 50→	if meta.Footprint != nil {
 51→		footprintJSON, err = json.Marshal(meta.Footprint)
 52→		if err != nil {
 53→			return nil, fmt.Errorf("marshal footprint: %w", err)
 54→		}
 55→	}
 56→
 57→	var energyFootJSON []byte
 58→	if meta.EnergyFootprint != nil {
 59→		energyFootJSON, err = json.Marshal(meta.EnergyFootprint)
 60→		if err != nil {
 61→			return nil, fmt.Errorf("marshal energy footprint: %w", err)
 62→		}
 63→	}
 64→
 65→	metricDataGz, err := compressJobData(data)
 66→	if err != nil {
 67→		return nil, fmt.Errorf("compress metric data: %w", err)
 68→	}
 69→
 70→	return &ParquetJobRow{
 71→		JobID:          meta.JobID,
 72→		Cluster:        meta.Cluster,
 73→		SubCluster:     meta.SubCluster,
 74→		Partition:      meta.Partition,
 75→		Project:        meta.Project,
 76→		User:           meta.User,
 77→		State:          string(meta.State),
 78→		StartTime:      meta.StartTime,
 79→		Duration:       meta.Duration,
 80→		Walltime:       meta.Walltime,
 81→		NumNodes:       meta.NumNodes,
 82→		NumHWThreads:   meta.NumHWThreads,
 83→		NumAcc:         meta.NumAcc,
 84→		Energy:         meta.Energy,
 85→		SMT:            meta.SMT,
 86→		ResourcesJSON:  resourcesJSON,
 87→		StatisticsJSON: statisticsJSON,
 88→		TagsJSON:       tagsJSON,
 89→		MetaDataJSON:   metaDataJSON,
 90→		FootprintJSON:  footprintJSON,
 91→		EnergyFootJSON: energyFootJSON,
 92→		MetricDataGz:   metricDataGz,
 93→	}, nil
 94→}
 95→
 96→// ParquetRowToJob converts a ParquetJobRow back into job metadata and metric data.
 97→// This is the reverse of JobToParquetRow.
 98→func ParquetRowToJob(row *ParquetJobRow) (*schema.Job, *schema.JobData, error) {
 99→	meta := &schema.Job{
100→		JobID:        row.JobID,
101→		Cluster:      row.Cluster,
102→		SubCluster:   row.SubCluster,
103→		Partition:    row.Partition,
104→		Project:      row.Project,
105→		User:         row.User,
106→		State:        schema.JobState(row.State),
107→		StartTime:    row.StartTime,
108→		Duration:     row.Duration,
109→		Walltime:     row.Walltime,
110→		NumNodes:     row.NumNodes,
111→		NumHWThreads: row.NumHWThreads,
112→		NumAcc:       row.NumAcc,
113→		Energy:       row.Energy,
114→		SMT:          row.SMT,
115→	}
116→
117→	if len(row.ResourcesJSON) > 0 {
118→		if err := json.Unmarshal(row.ResourcesJSON, &meta.Resources); err != nil {
119→			return nil, nil, fmt.Errorf("unmarshal resources: %w", err)
120→		}
121→	}
122→
123→	if len(row.StatisticsJSON) > 0 {
124→		if err := json.Unmarshal(row.StatisticsJSON, &meta.Statistics); err != nil {
125→			return nil, nil, fmt.Errorf("unmarshal statistics: %w", err)
126→		}
127→	}
128→
129→	if len(row.TagsJSON) > 0 {
130→		if err := json.Unmarshal(row.TagsJSON, &meta.Tags); err != nil {
131→			return nil, nil, fmt.Errorf("unmarshal tags: %w", err)
132→		}
133→	}
134→
135→	if len(row.MetaDataJSON) > 0 {
136→		if err := json.Unmarshal(row.MetaDataJSON, &meta.MetaData); err != nil {
137→			return nil, nil, fmt.Errorf("unmarshal metadata: %w", err)
138→		}
139→	}
140→
141→	if len(row.FootprintJSON) > 0 {
142→		if err := json.Unmarshal(row.FootprintJSON, &meta.Footprint); err != nil {
143→			return nil, nil, fmt.Errorf("unmarshal footprint: %w", err)
144→		}
145→	}
146→
147→	if len(row.EnergyFootJSON) > 0 {
148→		if err := json.Unmarshal(row.EnergyFootJSON, &meta.EnergyFootprint); err != nil {
149→			return nil, nil, fmt.Errorf("unmarshal energy footprint: %w", err)
150→		}
151→	}
152→
153→	data, err := decompressJobData(row.MetricDataGz)
154→	if err != nil {
155→		return nil, nil, fmt.Errorf("decompress metric data: %w", err)
156→	}
157→
158→	return meta, data, nil
159→}
160→
161→func decompressJobData(data []byte) (*schema.JobData, error) {
162→	gz, err := gzip.NewReader(bytes.NewReader(data))
163→	if err != nil {
164→		return nil, err
165→	}
166→	defer gz.Close()
167→
168→	var buf bytes.Buffer
169→	if _, err := buf.ReadFrom(gz); err != nil {
170→		return nil, err
171→	}
172→
173→	var jobData schema.JobData
174→	if err := json.Unmarshal(buf.Bytes(), &jobData); err != nil {
175→		return nil, err
176→	}
177→
178→	return &jobData, nil
179→}
180→
181→func compressJobData(data *schema.JobData) ([]byte, error) {
182→	jsonBytes, err := json.Marshal(data)
183→	if err != nil {
184→		return nil, err
185→	}
186→
187→	var buf bytes.Buffer
188→	gz, err := gzip.NewWriterLevel(&buf, gzip.BestCompression)
189→	if err != nil {
190→		return nil, err
191→	}
192→	if _, err := gz.Write(jsonBytes); err != nil {
193→		return nil, err
194→	}
195→	if err := gz.Close(); err != nil {
196→		return nil, err
197→	}
198→
199→	return buf.Bytes(), nil
200→}
