107→// transferJobsParquet converts jobs to Parquet format, organized by cluster.
108→func transferJobsParquet(jobs []*schema.Job, src archive.ArchiveBackend, target pqarchive.ParquetTarget, maxSizeMB int) error {
109→	cw := pqarchive.NewClusterAwareParquetWriter(target, maxSizeMB)
110→
111→	// Set cluster configs for all clusters referenced by jobs
112→	clustersDone := make(map[string]bool)
113→	for _, job := range jobs {
114→		if clustersDone[job.Cluster] {
115→			continue
116→		}
117→		clusterCfg, err := src.LoadClusterCfg(job.Cluster)
118→		if err != nil {
119→			cclog.Warnf("Retention: load cluster config %q: %v", job.Cluster, err)
120→		} else {
121→			cw.SetClusterConfig(job.Cluster, clusterCfg)
122→		}
123→		clustersDone[job.Cluster] = true
124→	}
125→
126→	for _, job := range jobs {
127→		meta, err := src.LoadJobMeta(job)
128→		if err != nil {
129→			cclog.Warnf("Retention: load meta for job %d: %v", job.JobID, err)
130→			continue
131→		}
132→		data, err := src.LoadJobData(job)
133→		if err != nil {
134→			cclog.Warnf("Retention: load data for job %d: %v", job.JobID, err)
135→			continue
136→		}
137→		row, err := pqarchive.JobToParquetRow(meta, &data)
138→		if err != nil {
139→			cclog.Warnf("Retention: convert job %d: %v", job.JobID, err)
140→			continue
141→		}
142→		if err := cw.AddJob(*row); err != nil {
143→			cclog.Errorf("Retention: add job %d to writer: %v", job.JobID, err)
144→			continue
145→		}
146→	}
147→
148→	return cw.Close()
149→}
