285→func RegisterRetentionMoveService(cfg Retention) {
286→	cclog.Infof("Register retention move service (format=%s, target=%s)", cfg.Format, cfg.TargetKind)
287→
288→	maxFileSizeMB := cfg.MaxFileSizeMB
289→	if maxFileSizeMB <= 0 {
290→		maxFileSizeMB = 512
291→	}
292→
293→	s.NewJob(gocron.DailyJob(1, gocron.NewAtTimes(gocron.NewAtTime(5, 0, 0))),
294→		gocron.NewTask(
295→			func() {
296→				startTime := time.Now().Unix() - int64(cfg.Age*24*3600)
297→				jobs, err := jobRepo.FindJobsBetween(0, startTime, cfg.OmitTagged)
298→				if err != nil {
299→					cclog.Warnf("Retention move: error finding jobs: %v", err)
300→					return
301→				}
302→				if len(jobs) == 0 {
303→					return
304→				}
305→
306→				cclog.Infof("Retention move: processing %d jobs", len(jobs))
307→				ar := archive.GetHandle()
308→
309→				switch cfg.Format {
310→				case "parquet":
311→					target, err := createParquetTarget(cfg)
312→					if err != nil {
313→						cclog.Errorf("Retention move: create parquet target: %v", err)
314→						return
315→					}
316→					if err := transferJobsParquet(jobs, ar, target, maxFileSizeMB); err != nil {
317→						cclog.Errorf("Retention move: parquet transfer: %v", err)
318→						return
319→					}
320→				default: // json
321→					dst, err := createTargetBackend(cfg)
322→					if err != nil {
323→						cclog.Errorf("Retention move: create target backend: %v", err)
324→						return
325→					}
326→					if err := transferJobsJSON(jobs, ar, dst); err != nil {
327→						cclog.Errorf("Retention move: json transfer: %v", err)
328→						return
329→					}
330→				}
331→
332→				cleanupAfterTransfer(jobs, startTime, cfg.IncludeDB, cfg.OmitTagged)
333→			}))
334→}
