 31→func parseDate(in string) int64 {
 32→	const shortForm = "2006-Jan-02"
 33→	loc, _ := time.LoadLocation("Local")
 34→	if in != "" {
 35→		t, err := time.ParseInLocation(shortForm, in, loc)
 36→		if err != nil {
 37→			cclog.Abortf("Archive Manager Main: Date parse failed with input: '%s'\nError: %s\n", in, err.Error())
 38→		}
 39→		return t.Unix()
 40→	}
 41→
 42→	return 0
 43→}
