 45→// parseArchivePath extracts the path from the source config JSON.
 46→func parseArchivePath(srcConfig string) (string, error) {
 47→	var config struct {
 48→		Kind string `json:"kind"`
 49→		Path string `json:"path"`
 50→	}
 51→	if err := json.Unmarshal([]byte(srcConfig), &config); err != nil {
 52→		return "", fmt.Errorf("failed to parse source config: %w", err)
 53→	}
 54→
 55→	if config.Path == "" {
 56→		return "", fmt.Errorf("no path found in source config")
 57→	}
 58→
 59→	return config.Path, nil
 60→}
