 62→// countJobsNative counts jobs using native Go filepath.WalkDir.
 63→// This is used as a fallback when fd/fdfind is not available.
 64→func countJobsNative(archivePath string) (int, error) {
 65→	count := 0
 66→	err := filepath.WalkDir(archivePath, func(path string, d fs.DirEntry, err error) error {
 67→		if err != nil {
 68→			return nil // Skip directories we can't access
 69→		}
 70→		if !d.IsDir() && d.Name() == "meta.json" {
 71→			count++
 72→		}
 73→		return nil
 74→	})
 75→	if err != nil {
 76→		return 0, fmt.Errorf("failed to walk directory: %w", err)
 77→	}
 78→
 79→	return count, nil
 80→}
 81→
 82→// countJobsWithFd counts jobs using the external fd command.
 83→func countJobsWithFd(fdPath, archivePath string) (int, error) {
 84→	fdCmd := exec.Command(fdPath, "meta.json", archivePath)
 85→	wcCmd := exec.Command("wc", "-l")
 86→
 87→	pipe, err := fdCmd.StdoutPipe()
 88→	if err != nil {
 89→		return 0, fmt.Errorf("failed to create pipe: %w", err)
 90→	}
 91→	wcCmd.Stdin = pipe
 92→
 93→	if err := fdCmd.Start(); err != nil {
 94→		return 0, fmt.Errorf("failed to start fd command: %w", err)
 95→	}
 96→
 97→	output, err := wcCmd.Output()
 98→	if err != nil {
 99→		return 0, fmt.Errorf("failed to run wc command: %w", err)
100→	}
101→
102→	if err := fdCmd.Wait(); err != nil {
103→		return 0, fmt.Errorf("fd command failed: %w", err)
104→	}
105→
106→	countStr := strings.TrimSpace(string(output))
107→	count, err := strconv.Atoi(countStr)
108→	if err != nil {
109→		return 0, fmt.Errorf("failed to parse count from wc output '%s': %w", countStr, err)
110→	}
111→
112→	return count, nil
113→}
