115→// countJobs counts the total number of jobs in the source archive.
116→// It tries to use external fd/fdfind command for speed, falling back to
117→// native Go filepath.WalkDir if neither is available.
118→// The srcConfig parameter should be the JSON configuration string containing the archive path.
119→func countJobs(srcConfig string) (int, error) {
120→	archivePath, err := parseArchivePath(srcConfig)
121→	if err != nil {
122→		return 0, err
123→	}
124→
125→	// Try fd first (common name)
126→	if fdPath, err := exec.LookPath("fd"); err == nil {
127→		return countJobsWithFd(fdPath, archivePath)
128→	}
129→
130→	// Try fdfind (Debian/Ubuntu package name)
131→	if fdPath, err := exec.LookPath("fdfind"); err == nil {
132→		return countJobsWithFd(fdPath, archivePath)
133→	}
134→
135→	// Fall back to native Go implementation
136→	cclog.Debug("fd/fdfind not found, using native Go file walker")
137→	return countJobsNative(archivePath)
138→}
