140→// formatDuration formats a duration as a human-readable string.
141→func formatDuration(d time.Duration) string {
142→	if d < time.Minute {
143→		return fmt.Sprintf("%ds", int(d.Seconds()))
144→	} else if d < time.Hour {
145→		return fmt.Sprintf("%dm%ds", int(d.Minutes()), int(d.Seconds())%60)
146→	}
147→	return fmt.Sprintf("%dh%dm", int(d.Hours()), int(d.Minutes())%60)
148→}
