150→// progressMeter displays import progress to the terminal.
151→type progressMeter struct {
152→	total     int
153→	processed int32
154→	imported  int32
155→	skipped   int32
156→	failed    int32
157→	startTime time.Time
158→	done      chan struct{}
159→}
160→
161→func newProgressMeter(total int) *progressMeter {
162→	return &progressMeter{
163→		total:     total,
164→		startTime: time.Now(),
165→		done:      make(chan struct{}),
166→	}
167→}
168→
169→func (p *progressMeter) start() {
170→	go func() {
171→		ticker := time.NewTicker(500 * time.Millisecond)
172→		defer ticker.Stop()
173→
174→		for {
175→			select {
176→			case <-ticker.C:
177→				p.render()
178→			case <-p.done:
179→				p.render()
180→				fmt.Println()
181→				return
182→			}
183→		}
184→	}()
185→}
186→
187→func (p *progressMeter) render() {
188→	processed := atomic.LoadInt32(&p.processed)
189→	imported := atomic.LoadInt32(&p.imported)
190→	skipped := atomic.LoadInt32(&p.skipped)
191→	failed := atomic.LoadInt32(&p.failed)
192→
193→	elapsed := time.Since(p.startTime)
194→	percent := float64(processed) / float64(p.total) * 100
195→	if p.total == 0 {
196→		percent = 0
197→	}
198→
199→	var eta string
200→	var throughput float64
201→	if processed > 0 {
202→		throughput = float64(processed) / elapsed.Seconds()
203→		remaining := float64(p.total-int(processed)) / throughput
204→		eta = formatDuration(time.Duration(remaining) * time.Second)
205→	} else {
206→		eta = "calculating..."
207→	}
208→
209→	barWidth := 30
210→	filled := int(float64(barWidth) * float64(processed) / float64(p.total))
211→	if p.total == 0 {
212→		filled = 0
213→	}
214→
215→	var bar strings.Builder
216→	for i := range barWidth {
217→		if i < filled {
218→			bar.WriteString("█")
219→		} else {
220→			bar.WriteString("░")
221→		}
222→	}
223→
224→	fmt.Printf("\r[%s] %5.1f%% | %d/%d | %.1f jobs/s | ETA: %s | ✓%d ○%d ✗%d   ",
225→		bar.String(), percent, processed, p.total, throughput, eta, imported, skipped, failed)
226→}
227→
228→func (p *progressMeter) stop() {
229→	close(p.done)
230→}
