232→// importArchive imports all jobs from a source archive backend to a destination archive backend.
233→// It uses parallel processing with a worker pool to improve performance.
234→// The import can be interrupted by CTRL-C (SIGINT) and will terminate gracefully.
235→// Returns the number of successfully imported jobs, failed jobs, and any error encountered.
236→func importArchive(srcBackend, dstBackend archive.ArchiveBackend, srcConfig string) (int, int, error) {
237→	cclog.Info("Starting parallel archive import...")
238→	cclog.Info("Press CTRL-C to interrupt (will finish current jobs before exiting)")
239→
240→	ctx, cancel := context.WithCancel(context.Background())
241→	defer cancel()
242→
243→	sigChan := make(chan os.Signal, 1)
244→	signal.Notify(sigChan, os.Interrupt, syscall.SIGTERM)
245→
246→	var interrupted atomic.Bool
247→
248→	go func() {
249→		<-sigChan
250→		cclog.Warn("Interrupt received, stopping import (finishing current jobs)...")
251→		interrupted.Store(true)
252→		cancel()
253→		// Stop listening for further signals to allow force quit with second CTRL-C
254→		signal.Stop(sigChan)
255→	}()
256→
257→	cclog.Info("Counting jobs in source archive (this may take a long time) ...")
258→	totalJobs, err := countJobs(srcConfig)
259→	if err != nil {
260→		return 0, 0, fmt.Errorf("failed to count jobs: %w", err)
261→	}
262→	cclog.Infof("Found %d jobs to process", totalJobs)
263→
264→	progress := newProgressMeter(totalJobs)
265→
266→	numWorkers := 4
267→	cclog.Infof("Using %d parallel workers", numWorkers)
268→
269→	jobs := make(chan archive.JobContainer, numWorkers*2)
270→
271→	var wg sync.WaitGroup
272→
273→	progress.start()
274→
275→	for i := range numWorkers {
276→		wg.Add(1)
277→		go func(workerID int) {
278→			defer wg.Done()
279→
280→			for job := range jobs {
281→				if job.Meta == nil {
282→					cclog.Warn("Skipping job with nil metadata")
283→					atomic.AddInt32(&progress.failed, 1)
284→					atomic.AddInt32(&progress.processed, 1)
285→					continue
286→				}
287→
288→				if job.Data == nil {
289→					cclog.Warnf("Job %d from cluster %s has no metric data, skipping",
290→						job.Meta.JobID, job.Meta.Cluster)
291→					atomic.AddInt32(&progress.failed, 1)
292→					atomic.AddInt32(&progress.processed, 1)
293→					continue
294→				}
295→
296→				if dstBackend.Exists(job.Meta) {
297→					cclog.Debugf("Job %d (cluster: %s, start: %d) already exists in destination, skipping",
298→						job.Meta.JobID, job.Meta.Cluster, job.Meta.StartTime)
299→					atomic.AddInt32(&progress.skipped, 1)
300→					atomic.AddInt32(&progress.processed, 1)
301→					continue
302→				}
303→
304→				if err := dstBackend.ImportJob(job.Meta, job.Data); err != nil {
305→					cclog.Errorf("Failed to import job %d from cluster %s: %s",
306→						job.Meta.JobID, job.Meta.Cluster, err.Error())
307→					atomic.AddInt32(&progress.failed, 1)
308→					atomic.AddInt32(&progress.processed, 1)
309→					continue
310→				}
311→
312→				atomic.AddInt32(&progress.imported, 1)
313→				atomic.AddInt32(&progress.processed, 1)
314→			}
315→		}(i)
316→	}
317→
318→	go func() {
319→		defer close(jobs)
320→
321→		clusters := srcBackend.GetClusters()
322→		for _, clusterName := range clusters {
323→			if ctx.Err() != nil {
324→				return
325→			}
326→
327→			clusterCfg, err := srcBackend.LoadClusterCfg(clusterName)
328→			if err != nil {
329→				cclog.Errorf("Failed to load cluster config for %s: %v", clusterName, err)
330→				continue
331→			}
332→
333→			if err := dstBackend.StoreClusterCfg(clusterName, clusterCfg); err != nil {
334→				cclog.Errorf("Failed to store cluster config for %s: %v", clusterName, err)
335→			} else {
336→				cclog.Infof("Imported cluster config for %s", clusterName)
337→			}
338→		}
339→
340→		for job := range srcBackend.Iter(true) {
341→			select {
342→			case <-ctx.Done():
343→				// Drain remaining items from iterator to avoid resource leak
344→				// but don't process them
345→				return
346→			case jobs <- job:
347→			}
348→		}
349→	}()
350→
351→	wg.Wait()
352→	progress.stop()
353→
354→	finalImported := int(atomic.LoadInt32(&progress.imported))
355→	finalFailed := int(atomic.LoadInt32(&progress.failed))
356→	finalSkipped := int(atomic.LoadInt32(&progress.skipped))
357→
358→	elapsed := time.Since(progress.startTime)
359→
360→	if interrupted.Load() {
361→		cclog.Warnf("Import interrupted after %s: %d jobs imported, %d skipped, %d failed",
362→			formatDuration(elapsed), finalImported, finalSkipped, finalFailed)
363→		return finalImported, finalFailed, fmt.Errorf("import interrupted by user")
364→	}
365→
366→	cclog.Infof("Import completed in %s: %d jobs imported, %d skipped, %d failed",
367→		formatDuration(elapsed), finalImported, finalSkipped, finalFailed)
368→
369→	if finalFailed > 0 {
370→		return finalImported, finalFailed, fmt.Errorf("%d jobs failed to import", finalFailed)
371→	}
372→
373→	return finalImported, finalFailed, nil
374→}
