425→// convertJSONToParquet converts a JSON archive backend to parquet format.
426→func convertJSONToParquet(srcBackend archive.ArchiveBackend, dstCfg sourceConfig, maxSizeMB int) error {
427→	target, err := createParquetTarget(dstCfg)
428→	if err != nil {
429→		return fmt.Errorf("create parquet target: %w", err)
430→	}
431→
432→	cw := pqarchive.NewClusterAwareParquetWriter(target, maxSizeMB)
433→
434→	// Transfer cluster configs
435→	for _, clusterName := range srcBackend.GetClusters() {
436→		clusterCfg, err := srcBackend.LoadClusterCfg(clusterName)
437→		if err != nil {
438→			cclog.Warnf("Convert: load cluster config %q: %v", clusterName, err)
439→			continue
440→		}
441→		cw.SetClusterConfig(clusterName, clusterCfg)
442→	}
443→
444→	converted := 0
445→	failed := 0
446→	startTime := time.Now()
447→
448→	for job := range srcBackend.Iter(true) {
449→		if job.Meta == nil {
450→			cclog.Warn("Skipping job with nil metadata")
451→			failed++
452→			continue
453→		}
454→		if job.Data == nil {
455→			cclog.Warnf("Job %d has no metric data, skipping", job.Meta.JobID)
456→			failed++
457→			continue
458→		}
459→
460→		row, err := pqarchive.JobToParquetRow(job.Meta, job.Data)
461→		if err != nil {
462→			cclog.Warnf("Convert job %d: %v", job.Meta.JobID, err)
463→			failed++
464→			continue
465→		}
466→		if err := cw.AddJob(*row); err != nil {
467→			cclog.Errorf("Add job %d to writer: %v", job.Meta.JobID, err)
468→			failed++
469→			continue
470→		}
471→		converted++
472→
473→		if converted%1000 == 0 {
474→			cclog.Infof("Converted %d jobs so far...", converted)
475→		}
476→	}
477→
478→	if err := cw.Close(); err != nil {
479→		return fmt.Errorf("close parquet writer: %w", err)
480→	}
481→
482→	elapsed := time.Since(startTime)
483→	cclog.Infof("JSON->Parquet conversion completed in %s: %d jobs converted, %d failed",
484→		formatDuration(elapsed), converted, failed)
485→	return nil
486→}
