488→// convertParquetToJSON converts a parquet archive to a JSON archive backend.
489→func convertParquetToJSON(srcCfg sourceConfig, dstBackend archive.ArchiveBackend) error {
490→	src, err := createParquetSource(srcCfg)
491→	if err != nil {
492→		return fmt.Errorf("create parquet source: %w", err)
493→	}
494→
495→	clusters, err := src.GetClusters()
496→	if err != nil {
497→		return fmt.Errorf("list clusters: %w", err)
498→	}
499→
500→	converted := 0
501→	failed := 0
502→	skipped := 0
503→	startTime := time.Now()
504→
505→	for _, cluster := range clusters {
506→		// Transfer cluster config
507→		clusterCfg, err := src.ReadClusterConfig(cluster)
508→		if err != nil {
509→			cclog.Warnf("Convert: read cluster config %q: %v", cluster, err)
510→		} else {
511→			if err := dstBackend.StoreClusterCfg(cluster, clusterCfg); err != nil {
512→				cclog.Warnf("Convert: store cluster config %q: %v", cluster, err)
513→			} else {
514→				cclog.Infof("Imported cluster config for %s", cluster)
515→			}
516→		}
517→
518→		// Read and convert parquet files
519→		files, err := src.ListParquetFiles(cluster)
520→		if err != nil {
521→			cclog.Errorf("Convert: list parquet files for %q: %v", cluster, err)
522→			continue
523→		}
524→
525→		for _, file := range files {
526→			data, err := src.ReadFile(file)
527→			if err != nil {
528→				cclog.Errorf("Convert: read file %q: %v", file, err)
529→				failed++
530→				continue
531→			}
532→
533→			rows, err := pqarchive.ReadParquetFile(data)
534→			if err != nil {
535→				cclog.Errorf("Convert: parse parquet file %q: %v", file, err)
536→				failed++
537→				continue
538→			}
539→
540→			cclog.Infof("Processing %s: %d jobs", file, len(rows))
541→
542→			for _, row := range rows {
543→				meta, jobData, err := pqarchive.ParquetRowToJob(&row)
544→				if err != nil {
545→					cclog.Warnf("Convert row to job: %v", err)
546→					failed++
547→					continue
548→				}
549→
550→				if dstBackend.Exists(meta) {
551→					skipped++
552→					continue
553→				}
554→
555→				if err := dstBackend.ImportJob(meta, jobData); err != nil {
556→					cclog.Warnf("Import job %d: %v", meta.JobID, err)
557→					failed++
558→					continue
559→				}
560→				converted++
561→			}
562→		}
563→	}
564→
565→	elapsed := time.Since(startTime)
566→	cclog.Infof("Parquet->JSON conversion completed in %s: %d jobs converted, %d skipped, %d failed",
567→		formatDuration(elapsed), converted, skipped, failed)
568→	return nil
569→}
