579→	flag.BoolVar(&flagLogDateTime, "logdate", false, "Set this flag to add date and time to log messages")
580→	flag.StringVar(&flagLogLevel, "loglevel", "info", "Sets the logging level: `[debug,info,warn (default),err,fatal,crit]`")
581→	flag.StringVar(&flagConfigFile, "config", "./config.json", "Specify alternative path to `config.json`")
582→	flag.StringVar(&flagRemoveCluster, "remove-cluster", "", "Remove cluster from archive and database")
583→	flag.StringVar(&flagRemoveBefore, "remove-before", "", "Remove all jobs with start time before date (Format: 2006-Jan-04)")
584→	flag.StringVar(&flagRemoveAfter, "remove-after", "", "Remove all jobs with start time after date (Format: 2006-Jan-04)")
585→	flag.BoolVar(&flagValidate, "validate", false, "Set this flag to validate a job archive against the json schema")
586→	flag.BoolVar(&flagImport, "import", false, "Import jobs from source archive to destination archive")
587→	flag.BoolVar(&flagConvert, "convert", false, "Convert archive between JSON and Parquet formats")
588→	flag.StringVar(&flagFormat, "format", "json", "Output format for conversion: 'json' or 'parquet'")
589→	flag.IntVar(&flagMaxFileSize, "max-file-size", 512, "Max parquet file size in MB (only for parquet output)")
590→	flag.StringVar(&flagSrcConfig, "src-config", "", "Source archive backend configuration (JSON), e.g. '{\"kind\":\"file\",\"path\":\"./archive\"}'")
591→	flag.StringVar(&flagDstConfig, "dst-config", "", "Destination archive backend configuration (JSON), e.g. '{\"kind\":\"sqlite\",\"dbPath\":\"./archive.db\"}'")
592→	flag.Parse()
593→
594→	archiveCfg := fmt.Sprintf("{\"kind\": \"file\",\"path\": \"%s\"}", srcPath)
595→
596→	cclog.Init(flagLogLevel, flagLogDateTime)
597→
598→	// Handle import mode
599→	if flagImport {
600→		if flagSrcConfig == "" || flagDstConfig == "" {
601→			cclog.Fatal("Both --src-config and --dst-config must be specified for import mode")
602→		}
603→
604→		cclog.Info("Import mode: initializing source and destination backends...")
605→
606→		// Initialize source backend
607→		srcBackend, err := archive.InitBackend(json.RawMessage(flagSrcConfig))
608→		if err != nil {
609→			cclog.Fatalf("Failed to initialize source backend: %s", err.Error())
610→		}
611→		cclog.Info("Source backend initialized successfully")
612→
613→		// Initialize destination backend
614→		dstBackend, err := archive.InitBackend(json.RawMessage(flagDstConfig))
615→		if err != nil {
616→			cclog.Fatalf("Failed to initialize destination backend: %s", err.Error())
617→		}
618→		cclog.Info("Destination backend initialized successfully")
619→
620→		// Perform import
621→		imported, failed, err := importArchive(srcBackend, dstBackend, flagSrcConfig)
622→		if err != nil {
623→			cclog.Errorf("Import completed with errors: %s", err.Error())
624→			if failed > 0 {
625→				os.Exit(1)
626→			}
627→		}
628→
629→		cclog.Infof("Import finished successfully: %d jobs imported", imported)
630→		os.Exit(0)
631→	}
632→
633→	// Handle convert mode
634→	if flagConvert {
635→		if flagSrcConfig == "" || flagDstConfig == "" {
636→			cclog.Fatal("Both --src-config and --dst-config must be specified for convert mode")
637→		}
638→
639→		var srcCfg, dstCfg sourceConfig
640→		if err := json.Unmarshal([]byte(flagSrcConfig), &srcCfg); err != nil {
641→			cclog.Fatalf("Failed to parse source config: %s", err.Error())
642→		}
643→		if err := json.Unmarshal([]byte(flagDstConfig), &dstCfg); err != nil {
644→			cclog.Fatalf("Failed to parse destination config: %s", err.Error())
645→		}
646→
647→		switch flagFormat {
648→		case "parquet":
649→			// JSON archive -> Parquet: source is an archive backend
650→			cclog.Info("Convert mode: JSON -> Parquet")
651→			srcBackend, err := archive.InitBackend(json.RawMessage(flagSrcConfig))
652→			if err != nil {
653→				cclog.Fatalf("Failed to initialize source backend: %s", err.Error())
654→			}
655→			if err := convertJSONToParquet(srcBackend, dstCfg, flagMaxFileSize); err != nil {
656→				cclog.Fatalf("Conversion failed: %s", err.Error())
657→			}
658→		case "json":
659→			// Parquet -> JSON archive: destination is an archive backend
660→			cclog.Info("Convert mode: Parquet -> JSON")
661→			dstBackend, err := archive.InitBackend(json.RawMessage(flagDstConfig))
662→			if err != nil {
663→				cclog.Fatalf("Failed to initialize destination backend: %s", err.Error())
664→			}
665→			if err := convertParquetToJSON(srcCfg, dstBackend); err != nil {
666→				cclog.Fatalf("Conversion failed: %s", err.Error())
667→			}
668→		default:
669→			cclog.Fatalf("Unknown format %q: must be 'json' or 'parquet'", flagFormat)
670→		}
671→
672→		cclog.Info("Conversion finished successfully")
673→		os.Exit(0)
674→	}
675→
676→	ccconf.Init(flagConfigFile)
677→
678→	// Load and check main configuration
679→	if cfg := ccconf.GetPackageConfig("main"); cfg != nil {
680→		config.Init(cfg)
681→	} else {
682→		cclog.Abort("Main configuration must be present")
683→	}
684→
685→	if err := archive.Init(json.RawMessage(archiveCfg)); err != nil {
686→		cclog.Fatal(err)
687→	}
688→	ar := archive.GetHandle()
689→
690→	if flagValidate {
691→		config.Keys.Validate = true
692→		for job := range ar.Iter(true) {
693→			cclog.Debugf("Validate %s - %d", job.Meta.Cluster, job.Meta.JobID)
694→		}
695→		os.Exit(0)
696→	}
697→
698→	if flagRemoveBefore != "" || flagRemoveAfter != "" {
699→		ar.Clean(parseDate(flagRemoveBefore), parseDate(flagRemoveAfter))
700→		os.Exit(0)
701→	}
702→
703→	ar.Info()
704→}
