 20→// ParquetMetricRow is the long-format schema for archived metric data.
 21→// One row per (host, metric, scope, scope_id, timestamp) data point.
 22→// Sorted by (cluster, hostname, metric, timestamp) for optimal compression.
 23→type ParquetMetricRow struct {
 24→	Cluster   string  `parquet:"cluster"`
 25→	Hostname  string  `parquet:"hostname"`
 26→	Metric    string  `parquet:"metric"`
 27→	Scope     string  `parquet:"scope"`
 28→	ScopeID   string  `parquet:"scope_id"`
 29→	Timestamp int64   `parquet:"timestamp"`
 30→	Frequency int64   `parquet:"frequency"`
 31→	Value     float32 `parquet:"value"`
 32→}
 33→
 34→// parseScopeFromName infers scope and scope_id from a child level name.
 35→// Examples: "socket0" → ("socket", "0"), "core12" → ("core", "12"),
 36→// "a0" (accelerator) → ("accelerator", "0").
 37→// If the name doesn't match known patterns, it's used as-is for scope with empty scope_id.
 38→func parseScopeFromName(name string) (string, string) {
 39→	prefixes := []struct {
 40→		prefix string
 41→		scope  string
 42→	}{
 43→		{"socket", "socket"},
 44→		{"memoryDomain", "memoryDomain"},
 45→		{"core", "core"},
 46→		{"hwthread", "hwthread"},
 47→		{"cpu", "hwthread"},
 48→		{"accelerator", "accelerator"},
 49→	}
 50→
 51→	for _, p := range prefixes {
 52→		if len(name) > len(p.prefix) && name[:len(p.prefix)] == p.prefix {
 53→			id := name[len(p.prefix):]
 54→			if len(id) > 0 && id[0] >= '0' && id[0] <= '9' {
 55→				return p.scope, id
 56→			}
 57→		}
 58→	}
 59→
 60→	return name, ""
 61→}
 62→
 63→// parquetArchiveWriter supports incremental writes to a Parquet file.
 64→// Uses streaming writes to avoid accumulating all rows in memory.
 65→type parquetArchiveWriter struct {
 66→	writer *pq.GenericWriter[ParquetMetricRow]
 67→	bw     *bufio.Writer
 68→	f      *os.File
 69→	batch  []ParquetMetricRow // reusable batch buffer
 70→	count  int
 71→}
 72→
 73→const parquetBatchSize = 1024
 74→
 75→// newParquetArchiveWriter creates a streaming Parquet writer with Zstd compression.
 76→func newParquetArchiveWriter(filename string) (*parquetArchiveWriter, error) {
 77→	if err := os.MkdirAll(filepath.Dir(filename), CheckpointDirPerms); err != nil {
 78→		return nil, fmt.Errorf("creating archive directory: %w", err)
 79→	}
 80→
 81→	f, err := os.OpenFile(filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
 82→	if err != nil {
 83→		return nil, fmt.Errorf("creating parquet file: %w", err)
 84→	}
 85→
 86→	bw := bufio.NewWriterSize(f, 1<<20) // 1MB write buffer
 87→
 88→	writer := pq.NewGenericWriter[ParquetMetricRow](bw,
 89→		pq.Compression(&pq.Zstd),
 90→	)
 91→
 92→	return &parquetArchiveWriter{
 93→		writer: writer,
 94→		bw:     bw,
 95→		f:      f,
 96→		batch:  make([]ParquetMetricRow, 0, parquetBatchSize),
 97→	}, nil
 98→}
 99→
100→// WriteCheckpointFile streams a CheckpointFile tree directly to Parquet rows,
101→// writing metrics in sorted order without materializing all rows in memory.
102→// Produces one row group per call (typically one host's data).
103→func (w *parquetArchiveWriter) WriteCheckpointFile(cf *CheckpointFile, cluster, hostname, scope, scopeID string) error {
104→	w.writeLevel(cf, cluster, hostname, scope, scopeID)
105→
106→	// Flush remaining batch
107→	if len(w.batch) > 0 {
108→		if _, err := w.writer.Write(w.batch); err != nil {
109→			return fmt.Errorf("writing parquet rows: %w", err)
110→		}
111→		w.count += len(w.batch)
112→		w.batch = w.batch[:0]
113→	}
114→
115→	if err := w.writer.Flush(); err != nil {
116→		return fmt.Errorf("flushing parquet row group: %w", err)
117→	}
118→
119→	return nil
120→}
121→
122→// writeLevel recursively writes metrics from a CheckpointFile level.
123→// Metric names and child names are sorted for deterministic, compression-friendly output.
124→func (w *parquetArchiveWriter) writeLevel(cf *CheckpointFile, cluster, hostname, scope, scopeID string) {
125→	// Sort metric names for deterministic order
126→	metricNames := make([]string, 0, len(cf.Metrics))
127→	for name := range cf.Metrics {
128→		metricNames = append(metricNames, name)
129→	}
130→	sort.Strings(metricNames)
131→
132→	for _, metricName := range metricNames {
133→		cm := cf.Metrics[metricName]
134→		ts := cm.Start
135→		for _, v := range cm.Data {
136→			if !v.IsNaN() {
137→				w.batch = append(w.batch, ParquetMetricRow{
138→					Cluster:   cluster,
139→					Hostname:  hostname,
140→					Metric:    metricName,
141→					Scope:     scope,
142→					ScopeID:   scopeID,
143→					Timestamp: ts,
144→					Frequency: cm.Frequency,
145→					Value:     float32(v),
146→				})
147→
148→				if len(w.batch) >= parquetBatchSize {
149→					w.writer.Write(w.batch)
150→					w.count += len(w.batch)
151→					w.batch = w.batch[:0]
152→				}
153→			}
154→			ts += cm.Frequency
155→		}
156→	}
157→
158→	// Sort child names for deterministic order
159→	childNames := make([]string, 0, len(cf.Children))
160→	for name := range cf.Children {
161→		childNames = append(childNames, name)
162→	}
163→	sort.Strings(childNames)
164→
165→	for _, childName := range childNames {
166→		childScope, childScopeID := parseScopeFromName(childName)
167→		w.writeLevel(cf.Children[childName], cluster, hostname, childScope, childScopeID)
168→	}
169→}
170→
171→// Close finalises the Parquet file (footer, buffered I/O, file handle).
172→func (w *parquetArchiveWriter) Close() error {
173→	if err := w.writer.Close(); err != nil {
174→		w.f.Close()
175→		return fmt.Errorf("closing parquet writer: %w", err)
176→	}
177→
178→	if err := w.bw.Flush(); err != nil {
179→		w.f.Close()
180→		return fmt.Errorf("flushing parquet file: %w", err)
181→	}
182→
183→	return w.f.Close()
184→}
185→
186→// loadCheckpointFileFromDisk reads a JSON or binary checkpoint file and returns
187→// a CheckpointFile. Used by the Parquet archiver to read checkpoint data
188→// before converting it to Parquet format.
189→func loadCheckpointFileFromDisk(filename string) (*CheckpointFile, error) {
190→	f, err := os.Open(filename)
191→	if err != nil {
192→		return nil, err
193→	}
194→	defer f.Close()
195→
196→	ext := filepath.Ext(filename)
197→	switch ext {
198→	case ".json":
199→		cf := &CheckpointFile{}
200→		br := bufio.NewReader(f)
201→		if err := json.NewDecoder(br).Decode(cf); err != nil {
202→			return nil, fmt.Errorf("decoding JSON checkpoint %s: %w", filename, err)
203→		}
204→		return cf, nil
205→
206→	case ".bin":
207→		br := bufio.NewReader(f)
208→		var magic uint32
209→		if err := binary.Read(br, binary.LittleEndian, &magic); err != nil {
210→			return nil, fmt.Errorf("reading magic from %s: %w", filename, err)
211→		}
212→		if magic != snapFileMagic {
213→			return nil, fmt.Errorf("invalid snapshot magic in %s: 0x%08X", filename, magic)
214→		}
215→		var fileFrom, fileTo int64
216→		if err := binary.Read(br, binary.LittleEndian, &fileFrom); err != nil {
217→			return nil, fmt.Errorf("reading from-timestamp from %s: %w", filename, err)
218→		}
219→		if err := binary.Read(br, binary.LittleEndian, &fileTo); err != nil {
220→			return nil, fmt.Errorf("reading to-timestamp from %s: %w", filename, err)
221→		}
222→		cf, err := readBinaryLevel(br)
223→		if err != nil {
224→			return nil, fmt.Errorf("reading binary level from %s: %w", filename, err)
225→		}
226→		cf.From = fileFrom
227→		cf.To = fileTo
228→		return cf, nil
229→
230→	default:
231→		return nil, fmt.Errorf("unsupported checkpoint extension: %s", ext)
232→	}
233→}
234→
235→// loadCheckpointFiles reads checkpoint files for a host directory and returns
236→// the loaded CheckpointFiles and their filenames. Processes one file at a time
237→// to avoid holding all checkpoint data in memory simultaneously.
238→func loadCheckpointFiles(dir string, from int64) ([]*CheckpointFile, []string, error) {
239→	entries, err := os.ReadDir(dir)
240→	if err != nil {
241→		return nil, nil, err
242→	}
243→
244→	files, err := findFiles(entries, from, false)
245→	if err != nil {
246→		return nil, nil, err
247→	}
248→
249→	if len(files) == 0 {
250→		return nil, nil, nil
251→	}
252→
253→	var checkpoints []*CheckpointFile
254→	var processedFiles []string
255→
256→	for _, checkpoint := range files {
257→		filename := filepath.Join(dir, checkpoint)
258→		cf, err := loadCheckpointFileFromDisk(filename)
259→		if err != nil {
260→			continue
261→		}
262→		checkpoints = append(checkpoints, cf)
263→		processedFiles = append(processedFiles, checkpoint)
264→	}
265→
266→	return checkpoints, processedFiles, nil
267→}
