 25→
 26→// ReadParquetFile reads all ParquetJobRow entries from parquet-encoded bytes.
 27→func ReadParquetFile(data []byte) ([]ParquetJobRow, error) {
 28→	file, err := pq.OpenFile(bytes.NewReader(data), int64(len(data)))
 29→	if err != nil {
 30→		return nil, fmt.Errorf("open parquet: %w", err)
 31→	}
 32→
 33→	reader := pq.NewGenericReader[ParquetJobRow](file)
 34→	defer reader.Close()
 35→
 36→	numRows := file.NumRows()
 37→	rows := make([]ParquetJobRow, numRows)
 38→	n, err := reader.Read(rows)
 39→	if err != nil && err != io.EOF {
 40→		return nil, fmt.Errorf("read parquet rows: %w", err)
 41→	}
 42→
 43→	return rows[:n], nil
 44→}
