 46→// ParquetSource abstracts reading parquet archives from different storage backends.
 47→type ParquetSource interface {
 48→	GetClusters() ([]string, error)
 49→	ListParquetFiles(cluster string) ([]string, error)
 50→	ReadFile(path string) ([]byte, error)
 51→	ReadClusterConfig(cluster string) (*schema.Cluster, error)
 52→}
 53→
 54→// FileParquetSource reads parquet archives from a local filesystem directory.
 55→type FileParquetSource struct {
 56→	path string
 57→}
 58→
 59→func NewFileParquetSource(path string) *FileParquetSource {
 60→	return &FileParquetSource{path: path}
 61→}
 62→
 63→func (fs *FileParquetSource) GetClusters() ([]string, error) {
 64→	entries, err := os.ReadDir(fs.path)
 65→	if err != nil {
 66→		return nil, fmt.Errorf("read directory: %w", err)
 67→	}
 68→
 69→	var clusters []string
 70→	for _, e := range entries {
 71→		if e.IsDir() {
 72→			clusters = append(clusters, e.Name())
 73→		}
 74→	}
 75→	return clusters, nil
 76→}
 77→
 78→func (fs *FileParquetSource) ListParquetFiles(cluster string) ([]string, error) {
 79→	dir := filepath.Join(fs.path, cluster)
 80→	entries, err := os.ReadDir(dir)
 81→	if err != nil {
 82→		return nil, fmt.Errorf("read cluster directory: %w", err)
 83→	}
 84→
 85→	var files []string
 86→	for _, e := range entries {
 87→		if !e.IsDir() && strings.HasSuffix(e.Name(), ".parquet") {
 88→			files = append(files, filepath.Join(cluster, e.Name()))
 89→		}
 90→	}
 91→	return files, nil
 92→}
 93→
 94→func (fs *FileParquetSource) ReadFile(path string) ([]byte, error) {
 95→	return os.ReadFile(filepath.Join(fs.path, path))
 96→}
 97→
 98→func (fs *FileParquetSource) ReadClusterConfig(cluster string) (*schema.Cluster, error) {
 99→	data, err := os.ReadFile(filepath.Join(fs.path, cluster, "cluster.json"))
100→	if err != nil {
101→		return nil, fmt.Errorf("read cluster.json: %w", err)
102→	}
103→	var cfg schema.Cluster
104→	if err := json.Unmarshal(data, &cfg); err != nil {
105→		return nil, fmt.Errorf("unmarshal cluster config: %w", err)
106→	}
107→	return &cfg, nil
108→}
