110→// S3ParquetSource reads parquet archives from an S3-compatible object store.
111→type S3ParquetSource struct {
112→	client *s3.Client
113→	bucket string
114→}
115→
116→func NewS3ParquetSource(cfg S3TargetConfig) (*S3ParquetSource, error) {
117→	if cfg.Bucket == "" {
118→		return nil, fmt.Errorf("S3 source: empty bucket name")
119→	}
120→
121→	region := cfg.Region
122→	if region == "" {
123→		region = "us-east-1"
124→	}
125→
126→	awsCfg, err := awsconfig.LoadDefaultConfig(context.Background(),
127→		awsconfig.WithRegion(region),
128→		awsconfig.WithCredentialsProvider(
129→			credentials.NewStaticCredentialsProvider(cfg.AccessKey, cfg.SecretKey, ""),
130→		),
131→	)
132→	if err != nil {
133→		return nil, fmt.Errorf("S3 source: load AWS config: %w", err)
134→	}
135→
136→	opts := func(o *s3.Options) {
137→		if cfg.Endpoint != "" {
138→			o.BaseEndpoint = aws.String(cfg.Endpoint)
139→		}
140→		o.UsePathStyle = cfg.UsePathStyle
141→	}
142→
143→	client := s3.NewFromConfig(awsCfg, opts)
144→	return &S3ParquetSource{client: client, bucket: cfg.Bucket}, nil
145→}
146→
147→func (ss *S3ParquetSource) GetClusters() ([]string, error) {
148→	ctx := context.Background()
149→	paginator := s3.NewListObjectsV2Paginator(ss.client, &s3.ListObjectsV2Input{
150→		Bucket:    aws.String(ss.bucket),
151→		Delimiter: aws.String("/"),
152→	})
153→
154→	var clusters []string
155→	for paginator.HasMorePages() {
156→		page, err := paginator.NextPage(ctx)
157→		if err != nil {
158→			return nil, fmt.Errorf("S3 source: list clusters: %w", err)
159→		}
160→		for _, prefix := range page.CommonPrefixes {
161→			if prefix.Prefix != nil {
162→				name := strings.TrimSuffix(*prefix.Prefix, "/")
163→				clusters = append(clusters, name)
164→			}
165→		}
166→	}
167→	return clusters, nil
168→}
169→
170→func (ss *S3ParquetSource) ListParquetFiles(cluster string) ([]string, error) {
171→	ctx := context.Background()
172→	prefix := cluster + "/"
173→	paginator := s3.NewListObjectsV2Paginator(ss.client, &s3.ListObjectsV2Input{
174→		Bucket: aws.String(ss.bucket),
175→		Prefix: aws.String(prefix),
176→	})
177→
178→	var files []string
179→	for paginator.HasMorePages() {
180→		page, err := paginator.NextPage(ctx)
181→		if err != nil {
182→			return nil, fmt.Errorf("S3 source: list parquet files: %w", err)
183→		}
184→		for _, obj := range page.Contents {
185→			if obj.Key != nil && strings.HasSuffix(*obj.Key, ".parquet") {
186→				files = append(files, *obj.Key)
187→			}
188→		}
189→	}
190→	return files, nil
191→}
192→
193→func (ss *S3ParquetSource) ReadFile(path string) ([]byte, error) {
194→	ctx := context.Background()
195→	result, err := ss.client.GetObject(ctx, &s3.GetObjectInput{
196→		Bucket: aws.String(ss.bucket),
197→		Key:    aws.String(path),
198→	})
199→	if err != nil {
200→		return nil, fmt.Errorf("S3 source: get object %q: %w", path, err)
