 20→// ParquetMetricRow is the long-format schema for archived metric data.
 21→// One row per (host, metric, scope, scope_id, timestamp) data point.
 22→// Sorted by (cluster, hostname, metric, timestamp) for optimal compression.
 23→type ParquetMetricRow struct {
 24→	Cluster   string  `parquet:"cluster"`
 25→	Hostname  string  `parquet:"hostname"`
 26→	Metric    string  `parquet:"metric"`
 27→	Scope     string  `parquet:"scope"`
 28→	ScopeID   string  `parquet:"scope_id"`
 29→	Timestamp int64   `parquet:"timestamp"`
 30→	Frequency int64   `parquet:"frequency"`
 31→	Value     float32 `parquet:"value"`
 32→}
 33→
 34→// parseScopeFromName infers scope and scope_id from a child level name.
 35→// Examples: "socket0" → ("socket", "0"), "core12" → ("core", "12"),
 36→// "a0" (accelerator) → ("accelerator", "0").
 37→// If the name doesn't match known patterns, it's used as-is for scope with empty scope_id.
 38→func parseScopeFromName(name string) (string, string) {
 39→	prefixes := []struct {
 40→		prefix string
 41→		scope  string
 42→	}{
 43→		{"socket", "socket"},
 44→		{"memoryDomain", "memoryDomain"},
 45→		{"core", "core"},
 46→		{"hwthread", "hwthread"},
 47→		{"cpu", "hwthread"},
 48→		{"accelerator", "accelerator"},
 49→	}
 50→
 51→	for _, p := range prefixes {
 52→		if len(name) > len(p.prefix) && name[:len(p.prefix)] == p.prefix {
 53→			id := name[len(p.prefix):]
 54→			if len(id) > 0 && id[0] >= '0' && id[0] <= '9' {
 55→				return p.scope, id
 56→			}
 57→		}
 58→	}
 59→
 60→	return name, ""
 61→}
