 63→// parquetArchiveWriter supports incremental writes to a Parquet file.
 64→// Uses streaming writes to avoid accumulating all rows in memory.
 65→type parquetArchiveWriter struct {
 66→	writer *pq.GenericWriter[ParquetMetricRow]
 67→	bw     *bufio.Writer
 68→	f      *os.File
 69→	batch  []ParquetMetricRow // reusable batch buffer
 70→	count  int
 71→}
 72→
 73→const parquetBatchSize = 1024
 74→
 75→// newParquetArchiveWriter creates a streaming Parquet writer with Zstd compression.
 76→func newParquetArchiveWriter(filename string) (*parquetArchiveWriter, error) {
 77→	if err := os.MkdirAll(filepath.Dir(filename), CheckpointDirPerms); err != nil {
 78→		return nil, fmt.Errorf("creating archive directory: %w", err)
 79→	}
 80→
 81→	f, err := os.OpenFile(filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
 82→	if err != nil {
 83→		return nil, fmt.Errorf("creating parquet file: %w", err)
 84→	}
 85→
 86→	bw := bufio.NewWriterSize(f, 1<<20) // 1MB write buffer
 87→
 88→	writer := pq.NewGenericWriter[ParquetMetricRow](bw,
 89→		pq.Compression(&pq.Zstd),
 90→	)
 91→
 92→	return &parquetArchiveWriter{
 93→		writer: writer,
 94→		bw:     bw,
 95→		f:      f,
 96→		batch:  make([]ParquetMetricRow, 0, parquetBatchSize),
 97→	}, nil
 98→}
