  5→
  6→package metricstore
  7→
  8→import (
  9→	"context"
 10→	"errors"
 11→	"fmt"
 12→	"os"
 13→	"path/filepath"
 14→	"sync"
 15→	"sync/atomic"
 16→	"time"
 17→
 18→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 19→)
 20→
 21→// Worker for either Archiving or Deleting files
 22→
 23→func CleanUp(wg *sync.WaitGroup, ctx context.Context) {
 24→	if Keys.Cleanup.Mode == "archive" {
 25→		cclog.Info("[METRICSTORE]> enable archive cleanup to parquet")
 26→		// Run as Archiver
 27→		cleanUpWorker(wg, ctx,
 28→			Keys.RetentionInMemory,
 29→			"archiving",
 30→			Keys.Cleanup.RootDir,
 31→			false,
 32→		)
 33→	} else {
 34→		// Run as Deleter
 35→		cleanUpWorker(wg, ctx,
 36→			Keys.RetentionInMemory,
 37→			"deleting",
 38→			"",
 39→			true,
 40→		)
 41→	}
 42→}
 43→
 44→// cleanUpWorker takes simple values to configure what it does
 45→func cleanUpWorker(wg *sync.WaitGroup, ctx context.Context, interval string, mode string, cleanupDir string, delete bool) {
 46→	wg.Go(func() {
 47→		d, err := time.ParseDuration(interval)
 48→		if err != nil {
 49→			cclog.Fatalf("[METRICSTORE]> error parsing %s interval duration: %v\n", mode, err)
 50→		}
 51→		if d <= 0 {
 52→			return
 53→		}
 54→
 55→		ticker := time.NewTicker(d)
 56→		defer ticker.Stop()
 57→
 58→		for {
 59→			select {
 60→			case <-ctx.Done():
 61→				return
 62→			case <-ticker.C:
 63→				t := time.Now().Add(-d)
 64→				cclog.Infof("[METRICSTORE]> start %s checkpoints (older than %s)...", mode, t.Format(time.RFC3339))
 65→
 66→				n, err := CleanupCheckpoints(Keys.Checkpoints.RootDir, cleanupDir, t.Unix(), delete)
 67→
 68→				if err != nil {
 69→					cclog.Errorf("[METRICSTORE]> %s failed: %s", mode, err.Error())
 70→				} else {
 71→					if delete {
 72→						cclog.Infof("[METRICSTORE]> done: %d checkpoints deleted", n)
 73→					} else {
 74→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files archived to parquet", n)
 75→					}
 76→				}
 77→			}
 78→		}
 79→	})
 80→}
 81→
 82→var ErrNoNewArchiveData error = errors.New("all data already archived")
 83→
 84→// CleanupCheckpoints deletes or archives all checkpoint files older than `from`.
 85→// When archiving, consolidates all hosts per cluster into a single Parquet file.
 86→func CleanupCheckpoints(checkpointsDir, cleanupDir string, from int64, deleteInstead bool) (int, error) {
 87→	if deleteInstead {
 88→		return deleteCheckpoints(checkpointsDir, from)
 89→	}
 90→
 91→	return archiveCheckpoints(checkpointsDir, cleanupDir, from)
 92→}
 93→
 94→// deleteCheckpoints removes checkpoint files older than `from` across all clusters/hosts.
 95→func deleteCheckpoints(checkpointsDir string, from int64) (int, error) {
 96→	entries1, err := os.ReadDir(checkpointsDir)
 97→	if err != nil {
 98→		return 0, err
 99→	}
100→
101→	type workItem struct {
102→		dir           string
103→		cluster, host string
104→	}
105→
106→	var wg sync.WaitGroup
107→	n, errs := int32(0), int32(0)
108→	work := make(chan workItem, Keys.NumWorkers)
109→
110→	wg.Add(Keys.NumWorkers)
111→	for worker := 0; worker < Keys.NumWorkers; worker++ {
112→		go func() {
113→			defer wg.Done()
114→			for item := range work {
115→				entries, err := os.ReadDir(item.dir)
116→				if err != nil {
117→					cclog.Errorf("error reading %s/%s: %s", item.cluster, item.host, err.Error())
118→					atomic.AddInt32(&errs, 1)
119→					continue
120→				}
121→
122→				files, err := findFiles(entries, from, false)
123→				if err != nil {
124→					cclog.Errorf("error finding files in %s/%s: %s", item.cluster, item.host, err.Error())
125→					atomic.AddInt32(&errs, 1)
126→					continue
127→				}
128→
129→				for _, checkpoint := range files {
130→					if err := os.Remove(filepath.Join(item.dir, checkpoint)); err != nil {
131→						cclog.Errorf("error deleting %s/%s/%s: %s", item.cluster, item.host, checkpoint, err.Error())
132→						atomic.AddInt32(&errs, 1)
133→					} else {
134→						atomic.AddInt32(&n, 1)
135→					}
136→				}
137→			}
138→		}()
139→	}
140→
141→	for _, de1 := range entries1 {
142→		entries2, e := os.ReadDir(filepath.Join(checkpointsDir, de1.Name()))
143→		if e != nil {
144→			err = e
145→			continue
146→		}
147→
148→		for _, de2 := range entries2 {
149→			work <- workItem{
150→				dir:     filepath.Join(checkpointsDir, de1.Name(), de2.Name()),
151→				cluster: de1.Name(),
152→				host:    de2.Name(),
153→			}
154→		}
155→	}
156→
157→	close(work)
158→	wg.Wait()
159→
160→	if err != nil {
161→		return int(n), err
162→	}
163→	if errs > 0 {
164→		return int(n), fmt.Errorf("%d errors happened while deleting (%d successes)", errs, n)
165→	}
166→	return int(n), nil
167→}
168→
169→// archiveCheckpoints archives checkpoint files to Parquet format.
170→// Produces one Parquet file per cluster: <cleanupDir>/<cluster>/<timestamp>.parquet
171→// Workers load checkpoint files from disk and send CheckpointFile trees on a
172→// back-pressured channel. The main thread streams each tree directly to Parquet
173→// rows without materializing all rows in memory.
174→func archiveCheckpoints(checkpointsDir, cleanupDir string, from int64) (int, error) {
175→	cclog.Info("[METRICSTORE]> start archiving checkpoints to parquet")
176→	startTime := time.Now()
177→
178→	clusterEntries, err := os.ReadDir(checkpointsDir)
179→	if err != nil {
180→		return 0, err
181→	}
182→
183→	totalFiles := 0
184→
185→	for _, clusterEntry := range clusterEntries {
186→		if !clusterEntry.IsDir() {
187→			continue
188→		}
189→
190→		cluster := clusterEntry.Name()
191→		hostEntries, err := os.ReadDir(filepath.Join(checkpointsDir, cluster))
192→		if err != nil {
193→			return totalFiles, err
194→		}
195→
196→		// Workers load checkpoint files from disk; main thread writes to parquet.
197→		type hostResult struct {
198→			checkpoints []*CheckpointFile
199→			hostname    string
200→			files       []string // checkpoint filenames to delete after successful write
201→			dir         string   // checkpoint directory for this host
202→		}
203→
204→		// Small buffer provides back-pressure: at most NumWorkers+2 results in flight.
205→		results := make(chan hostResult, 2)
206→		work := make(chan struct {
207→			dir, host string
208→		}, Keys.NumWorkers)
209→
210→		var wg sync.WaitGroup
211→		errs := int32(0)
212→
213→		wg.Add(Keys.NumWorkers)
214→		for w := 0; w < Keys.NumWorkers; w++ {
215→			go func() {
216→				defer wg.Done()
217→				for item := range work {
218→					checkpoints, files, err := loadCheckpointFiles(item.dir, from)
219→					if err != nil {
220→						cclog.Errorf("[METRICSTORE]> error reading checkpoints for %s/%s: %s", cluster, item.host, err.Error())
221→						atomic.AddInt32(&errs, 1)
222→						continue
223→					}
224→					if len(checkpoints) > 0 {
225→						results <- hostResult{
226→							checkpoints: checkpoints,
227→							hostname:    item.host,
228→							files:       files,
229→							dir:         item.dir,
230→						}
231→					}
232→				}
233→			}()
234→		}
235→
236→		go func() {
237→			for _, hostEntry := range hostEntries {
238→				if !hostEntry.IsDir() {
239→					continue
240→				}
241→				dir := filepath.Join(checkpointsDir, cluster, hostEntry.Name())
242→				work <- struct {
243→					dir, host string
244→				}{dir: dir, host: hostEntry.Name()}
245→			}
246→			close(work)
247→			wg.Wait()
248→			close(results)
249→		}()
250→
251→		// Open streaming writer and write each host's checkpoint files as a row group
252→		parquetFile := filepath.Join(cleanupDir, cluster, fmt.Sprintf("%d.parquet", from))
253→		writer, err := newParquetArchiveWriter(parquetFile)
254→		if err != nil {
255→			// Drain results channel to unblock workers
256→			for range results {
257→			}
258→			return totalFiles, fmt.Errorf("creating parquet writer for cluster %s: %w", cluster, err)
259→		}
260→
261→		type deleteItem struct {
262→			dir   string
263→			files []string
264→		}
265→		var toDelete []deleteItem
266→		writeErr := error(nil)
267→
268→		for r := range results {
269→			if writeErr == nil {
270→				// Stream each checkpoint file directly to parquet rows.
271→				// Each checkpoint is processed and discarded before the next.
272→				for _, cf := range r.checkpoints {
273→					if err := writer.WriteCheckpointFile(cf, cluster, r.hostname, "node", ""); err != nil {
274→						writeErr = err
275→						break
276→					}
277→				}
278→			}
279→			// Always track files for deletion (even if write failed, we still drain)
280→			toDelete = append(toDelete, deleteItem{dir: r.dir, files: r.files})
281→		}
282→
283→		if err := writer.Close(); err != nil && writeErr == nil {
284→			writeErr = err
285→		}
286→
287→		if errs > 0 {
288→			return totalFiles, fmt.Errorf("%d errors reading checkpoints for cluster %s", errs, cluster)
289→		}
290→
291→		if writer.count == 0 {
292→			// No data written — remove empty file
293→			os.Remove(parquetFile)
294→			continue
295→		}
296→
297→		if writeErr != nil {
298→			os.Remove(parquetFile)
299→			return totalFiles, fmt.Errorf("writing parquet archive for cluster %s: %w", cluster, writeErr)
300→		}
301→
302→		// Delete archived checkpoint files
303→		for _, item := range toDelete {
304→			for _, file := range item.files {
305→				filename := filepath.Join(item.dir, file)
306→				if err := os.Remove(filename); err != nil {
307→					cclog.Warnf("[METRICSTORE]> could not remove archived checkpoint %s: %v", filename, err)
308→				} else {
309→					totalFiles++
310→				}
311→			}
312→		}
313→
314→		cclog.Infof("[METRICSTORE]> archived %d rows from %d files for cluster %s to %s",
315→			writer.count, totalFiles, cluster, parquetFile)
316→	}
317→
318→	cclog.Infof("[METRICSTORE]> archiving checkpoints completed in %s (%d files)", time.Since(startTime).Round(time.Millisecond), totalFiles)
319→	return totalFiles, nil
320→}
